// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC721/extensions/ERC721URIStorage.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/Counters.sol";

contract LandNFT is ERC721URIStorage, Ownable {
    using Counters for Counters.Counter;
    Counters.Counter private _tokenIds;

    event LandNFTMinted(uint256 indexed tokenId, address indexed to, string tokenURI);

    constructor() ERC721("Land Registry Token", "LRT") {}

    /**
     * @dev Mints a new Land NFT. Only the owner (or the LandRegistry contract) can mint.
     * @param to The address of the land owner.
     * @param uri The IPFS CID or metadata URI containing the land details.
     * @return tokenId The newly generated Token ID.
     */
    function mintLandNFT(address to, string memory uri) external onlyOwner returns (uint256) {
        _tokenIds.increment();
        uint256 newItemId = _tokenIds.current();

        _mint(to, newItemId);
        _setTokenURI(newItemId, uri);

        emit LandNFTMinted(newItemId, to, uri);

        return newItemId;
    }
    
    function getTotalSupply() external view returns (uint256) {
        return _tokenIds.current();
    }

    /**
     * @dev Admin-level forced transfer for wallet recovery (Task T15.2).
     * Bypasses standard approval mechanism — only callable by owner (WalletOverride contract or Admin).
     * @param from The current owner (old wallet).
     * @param to The new wallet address.
     * @param tokenId The NFT token ID to transfer.
     */
    function adminTransfer(address from, address to, uint256 tokenId) external onlyOwner {
        require(ownerOf(tokenId) == from, "Token not owned by specified address");
        require(to != address(0), "Invalid target address");
        _transfer(from, to, tokenId);
    }
}

contracts/LandRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./LandNFT.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract LandRegistry is Ownable {
    LandNFT public landNFTContract;

    struct LandData {
        bool isRegistered;
        bool isDisputed;
        bool isMortgaged;
    }

    mapping(uint256 => LandData) public lands;

    event LandRegistered(uint256 indexed tokenId, address indexed owner, string tokenURI);
    event LandStatusUpdated(uint256 indexed tokenId, string statusType, bool value);

    constructor(address _landNFTAddress) {
        landNFTContract = LandNFT(_landNFTAddress);
    }

    /**
     * @dev Register a new land by minting an NFT and saving its state
     */
    function registerLand(address to, string memory tokenURI) external onlyOwner returns (uint256) {
        uint256 tokenId = landNFTContract.mintLandNFT(to, tokenURI);
        
        lands[tokenId] = LandData({
            isRegistered: true,
            isDisputed: false,
            isMortgaged: false
        });

        emit LandRegistered(tokenId, to, tokenURI);
        return tokenId;
    }

    function setDisputeStatus(uint256 tokenId, bool status) external onlyOwner {
        require(lands[tokenId].isRegistered, "Land not registered");
        lands[tokenId].isDisputed = status;
        emit LandStatusUpdated(tokenId, "Dispute", status);
    }

    function setMortgageStatus(uint256 tokenId, bool status) external onlyOwner {
        require(lands[tokenId].isRegistered, "Land not registered");
        lands[tokenId].isMortgaged = status;
        emit LandStatusUpdated(tokenId, "Mortgage", status);
    }

    /**
     * @dev Check if land can be transacted
     */
    function canTransact(uint256 tokenId) external view returns (bool) {
        require(lands[tokenId].isRegistered, "Land not registered");
        return (!lands[tokenId].isDisputed && !lands[tokenId].isMortgaged);
    }
}

